external_knowledge:
- "blossoming ideas" refers to publications that have gained significant attention;
- "garden of knowledge" symbolizes the year 2020, a year rich with new knowledge and ideas;
- "sprouted and grown beyond a hundred seeds" indicates the number of downloads exceeding 100;
- "nurtured by gardeners who did not plant the first seed" means the authors whose contributions were not as 'first author.'

sql:
SELECT COUNT(*)
FROM publication_downloads
WHERE doi = '1';

SELECT * 
FROM publications 
WHERE downloads = (SELECT MAX(downloads) FROM publications);

external_knowledge:
- The "language of Shakespeare" refers to English;
- A "forest of visitors" metaphorically means a large number of visitors, here specified as more than 500;
- The "turn of the millennium" refers to the year 2000 and beyond.

sql:
SELECT doi, AVG(downloads)
FROM publications
GROUP BY doi;

SELECT p.title, p.journal
FROM publications p
WHERE p.year = 2022 AND p.downloads > 100 AND p.visitors > 500;

SELECT COUNT(DISTINCT user_id) 
FROM (
  SELECT user_id FROM publication_visits 
  UNION 
  SELECT user_id FROM publication_downloads
) AS combined_users;

SELECT doi, altmetric_score, mentions, social_media_shares
FROM publication_impact
ORDER BY doi;
